/**
 * Media-asset helpers — upload generated bytes to Supabase Storage, mint a
 * public URL, and insert a row into the media_assets table.
 *
 * Server-side only (uses the service-role client to bypass RLS for inserts
 * across buckets; the row is then bound to user_id for read-side RLS).
 */

import { createServiceRoleClient } from './supabase/server';

export type MediaKind = 'audio' | 'image' | 'video';

export type StoredAsset = {
  id: string;
  publicUrl: string;
  storagePath: string;
  bucket: string;
};

const BUCKETS: Record<MediaKind, string> = {
  audio: 'workbook-audio',
  image: 'workbook-generated',
  video: 'workbook-video',
};

function extFor(kind: MediaKind, contentType: string): string {
  if (kind === 'audio') return contentType.includes('wav') ? 'wav' : 'mp3';
  if (kind === 'image') return contentType.includes('png') ? 'png' : contentType.includes('webp') ? 'webp' : 'jpg';
  return 'mp4';
}

/**
 * Upload bytes for a generated asset. Stores under
 *   <bucket>/<user_id>/<workbook_id|'_'>/<uuid>.<ext>
 * and inserts a media_assets row.
 */
export async function storeBytes(params: {
  userId: string;
  workbookId?: string | null;
  kind: MediaKind;
  provider: string;
  providerModel?: string;
  bytes: Buffer;
  contentType: string;
  prompt?: string;
  durationMs?: number;
  width?: number;
  height?: number;
  meta?: Record<string, unknown>;
}): Promise<StoredAsset> {
  const supa = createServiceRoleClient();
  const bucket = BUCKETS[params.kind];
  const ext = extFor(params.kind, params.contentType);
  const id = crypto.randomUUID();
  const path = `${params.userId}/${params.workbookId ?? '_'}/${id}.${ext}`;

  const { error: upErr } = await supa.storage.from(bucket).upload(path, params.bytes, {
    contentType: params.contentType,
    upsert: false,
  });
  if (upErr) throw new Error(`Storage upload failed: ${upErr.message}`);

  const { data: pub } = supa.storage.from(bucket).getPublicUrl(path);
  const publicUrl = pub.publicUrl;

  const { data: row, error: insErr } = await supa
    .from('media_assets')
    .insert({
      user_id: params.userId,
      workbook_id: params.workbookId ?? null,
      kind: params.kind,
      provider: params.provider,
      provider_model: params.providerModel ?? null,
      storage_path: path,
      public_url: publicUrl,
      prompt: params.prompt ?? null,
      duration_ms: params.durationMs ?? null,
      width: params.width ?? null,
      height: params.height ?? null,
      meta: params.meta ?? {},
    })
    .select('id')
    .single();
  if (insErr) throw new Error(`media_assets insert failed: ${insErr.message}`);

  return { id: row.id as string, publicUrl, storagePath: path, bucket };
}

/**
 * Fetch a remote URL (e.g. Replicate output) and store it as a media asset.
 */
export async function storeRemoteUrl(params: {
  userId: string;
  workbookId?: string | null;
  kind: MediaKind;
  provider: string;
  providerModel?: string;
  url: string;
  prompt?: string;
  meta?: Record<string, unknown>;
}): Promise<StoredAsset> {
  const res = await fetch(params.url);
  if (!res.ok) throw new Error(`Fetch remote asset ${res.status}: ${params.url}`);
  const contentType = res.headers.get('content-type') || (params.kind === 'video' ? 'video/mp4' : 'image/webp');
  const bytes = Buffer.from(await res.arrayBuffer());
  return storeBytes({
    userId: params.userId,
    workbookId: params.workbookId,
    kind: params.kind,
    provider: params.provider,
    providerModel: params.providerModel,
    bytes,
    contentType,
    prompt: params.prompt,
    meta: params.meta,
  });
}
